    checks.push({
      name: "Semantic HTML Structure",
      status: sem.usesSemanticHtml && sem.headingHierarchyValid ? "PASS" : sem.usesSemanticHtml || sem.headingHierarchyValid ? "WARNING" : "FAIL",
      details: [
