} from "@shared/schema";

const formSchema = z.object({
  url: z.string().url("Please enter a valid URL"),
});

type ActiveTab = "analyze" | "compare";

export default function AeoAnalyzerPage() {
  const [analysis, setAnalysis] = useState<AeoAnalysis | null>(null);
