}

function CitationLikelihoodCard({ citation }: { citation: CitationLikelihood }) {
  const ratingColors: Record<string, string> = {
    "Very Likely": "text-green-600",
    "Likely": "text-blue-600",
    "Possible": "text-yellow-600",
    "Unlikely": "text-red-600",
