import { SeoAnalysis } from "@shared/schema";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { 
  Settings, 
  Gauge, 
  Shield, 
  Search, 
  FileText,
  ArrowRight 
} from "lucide-react";

interface CategoryCardsProps {
  analysis: SeoAnalysis;
  onViewDetails?: (tab: string) => void;
}

export default function CategoryCards({ analysis, onViewDetails }: CategoryCardsProps) {
  const categories = [
    {
      name: "Technical SEO",
      tab: "technical",
      score: analysis.technicalScore,
      icon: Settings,
      color: "blue",
      checks: [
        { name: "Indexing/Crawling", status: "PASS" },
        { name: "Robots.txt", status: "PASS" },
        { name: "Sitemap", status: "WARNING" },
      ],
    },
    {
      name: "Performance",
      tab: "performance",
      score: analysis.performanceScore,
      icon: Gauge,
      color: "green",
      checks: [
        { name: "Core Web Vitals", status: analysis.performanceScore >= 70 ? "PASS" : "NEEDS WORK" },
        { name: "Mobile Friendly", status: "PASS" },
        { name: "Page Speed", status: analysis.performanceScore >= 80 ? "PASS" : "FAIL" },
      ],
    },
    {
      name: "Accessibility",
      tab: "accessibility",
      score: analysis.accessibilityScore,
      icon: Shield,
      color: "purple",
      checks: [
        { name: "ARIA Labels", status: "PASS" },
        { name: "Text Contrast", status: "PASS" },
        { name: "Keyboard Navigation", status: "WARNING" },
      ],
    },
    {
      name: "Keywords",
      tab: "keywords",
      score: analysis.keywordScore,
      icon: Search,
      color: "orange",
      checks: [
        { name: "Meta Title", status: "PASS" },
        { name: "Meta Description", status: "PASS" },
        { name: "Heading Structure", status: "WARNING" },
      ],
    },
    {
      name: "Content Quality",
      tab: "content",
      score: analysis.contentScore,
      icon: FileText,
      color: "indigo",
      checks: [
        { name: "Word Count", status: "PASS" },
        { name: "Readability", status: "PASS" },
        { name: "Image Alt Tags", status: "WARNING" },
      ],
    },
  ];

  const getScoreColor = (score: number) => {
    if (score >= 80) return "text-green-600";
    if (score >= 60) return "text-yellow-600";
    return "text-red-600";
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case "PASS":
        return "text-green-600";
      case "WARNING":
        return "text-yellow-600";
      case "NEEDS WORK":
        return "text-yellow-600";
      case "FAIL":
        return "text-red-600";
      default:
        return "text-muted-foreground";
    }
  };

  const getIconBg = (color: string) => {
    switch (color) {
      case "blue":
        return "bg-blue-100";
      case "green":
        return "bg-green-100";
      case "purple":
        return "bg-purple-100";
      case "orange":
        return "bg-orange-100";
      case "indigo":
        return "bg-indigo-100";
      default:
        return "bg-gray-100";
    }
  };

  const getIconColor = (color: string) => {
    switch (color) {
      case "blue":
        return "text-blue-600";
      case "green":
        return "text-green-600";
      case "purple":
        return "text-purple-600";
      case "orange":
        return "text-orange-600";
      case "indigo":
        return "text-indigo-600";
      default:
        return "text-gray-600";
    }
  };

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6 mb-8">
      {categories.map((category, index) => {
        const IconComponent = category.icon;
        return (
          <Card key={category.name} className="rounded-xl border border-border shadow-sm p-6">
            <CardContent className="p-0">
              <div className="flex items-center justify-between mb-4">
                <div className="flex items-center space-x-3">
                  <div className={`w-10 h-10 ${getIconBg(category.color)} rounded-lg flex items-center justify-center`}>
                    <IconComponent className={`w-5 h-5 ${getIconColor(category.color)}`} />
                  </div>
                  <h3 className="text-lg font-semibold text-foreground">{category.name}</h3>
                </div>
                <span 
                  className={`text-2xl font-bold ${getScoreColor(category.score)}`}
                  data-testid={`text-${category.name.toLowerCase().replace(/\s+/g, '-')}-score`}
                >
                  {category.score}
                </span>
              </div>
              <div className="space-y-2">
                {category.checks.map((check) => (
                  <div key={check.name} className="flex items-center justify-between text-sm">
                    <span className="text-muted-foreground">{check.name}</span>
                    <span className={`font-medium ${getStatusColor(check.status)}`}>
                      {check.status}
                    </span>
                  </div>
                ))}
              </div>
              <Button 
                variant="ghost" 
                className="w-full mt-4 text-primary hover:text-primary/80 text-sm font-medium justify-center"
                data-testid={`button-view-${category.name.toLowerCase().replace(/\s+/g, '-')}-details`}
                onClick={() => onViewDetails?.(category.tab)}
              >
                View Details <ArrowRight className="w-4 h-4 ml-1" />
              </Button>
            </CardContent>
          </Card>
        );
      })}
    </div>
  );
}

server/services/mailerlite.ts.content:
const MAILERLITE_API_KEY = process.env.MAILERLITE_API_KEY;
const MAILERLITE_API_URL = 'https://connect.mailerlite.com/api';

const localEmails: { email: string; tags: string[]; createdAt: Date }[] = [];

export function isMailerLiteConfigured(): boolean {
  return !!MAILERLITE_API_KEY;
}

export async function addSubscriber(email: string, tags: string[] = ['seo-analyzer']): Promise<boolean> {
  localEmails.push({ email, tags, createdAt: new Date() });

  if (!MAILERLITE_API_KEY) {
    console.log(`[MailerLite] Not configured. Email stored locally: ${email}`);
    return true;
  }

  try {
    const response = await fetch(`${MAILERLITE_API_URL}/subscribers`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${MAILERLITE_API_KEY}`,
      },
      body: JSON.stringify({
        email,
        groups: [],
        status: 'active',
      }),
    });

    if (!response.ok) {
      console.error(`[MailerLite] Failed to add subscriber: ${response.status}`);
      return false;
    }

    console.log(`[MailerLite] Subscriber added: ${email}`);
    return true;
  } catch (error) {
    console.error(`[MailerLite] Error:`, error);
    return false;
  }
}

export function getLocalEmails(): typeof localEmails {
  return [...localEmails];
}

