import PDFDocument from "pdfkit";
import { SeoAnalysis } from "@shared/schema";

export async function generatePdfReport(analysis: SeoAnalysis): Promise<Buffer> {
  return new Promise((resolve, reject) => {
    try {
      const doc = new PDFDocument({ 
        margin: 30,
        size: 'A4',
        info: {
          Title: `SEO Analysis Report - ${analysis.url}`,
          Author: 'SEO Analyzer Pro',
          Subject: 'Website SEO Performance Analysis',
          Keywords: 'SEO, Analysis, Website Optimization, Performance'
        }
      });
      const buffers: Buffer[] = [];

      doc.on('data', (chunk: Buffer) => buffers.push(chunk));
      doc.on('end', () => resolve(Buffer.concat(buffers)));
      doc.on('error', reject);

      // Web App Style Header - Primary Blue
      const headerHeight = 80;
      doc.rect(0, 0, doc.page.width, headerHeight).fill(colors.primary);

      // Logo area (matching web app)
      doc.circle(50, 25, 12).fill('white');
      doc.fillColor(colors.primary).fontSize(10).text('S', 46, 20);

      doc.fillColor('white')
         .fontSize(24)
         .font('Helvetica-Bold')
         .text('SEO Analyzer Pro', 75, 20);

      doc.fontSize(12)
         .font('Helvetica')
         .text(`Analysis Report for ${analysis.url}`, 75, 45);

      doc.fontSize(10)
         .text(`Generated ${new Date().toLocaleDateString('en-US', { 
           year: 'numeric', month: 'long', day: 'numeric' 
         })}`, doc.page.width - 150, 45);

      doc.fillColor(colors.foreground);
      doc.y = headerHeight + 20;

      // Overall Score Card (matching web app layout)
      createCard(doc, doc.y, 500, 100);

      // Progress ring (matching web app)
      const centerX = 80;
      const centerY = doc.y + 50;
      const radius = 35;

      // Background circle
      doc.circle(centerX, centerY, radius)
         .lineWidth(6)
         .strokeColor(colors.muted)
         .stroke();

      // Progress circle
      const circumference = 2 * Math.PI * radius;
      const progress = (analysis.overallScore / 100) * circumference;
      doc.circle(centerX, centerY, radius)
         .lineWidth(6)
         .strokeColor(getScoreColor(analysis.overallScore))
         .dash(progress, circumference - progress)
         .stroke();

      // Score text (matching web app)
      doc.fillColor(colors.foreground)
         .fontSize(28)
         .font('Helvetica-Bold')
         .text(`${analysis.overallScore}`, centerX - 18, centerY - 10);

      // Score description (matching web app)
      const performanceLevel = getPerformanceLevel(analysis.overallScore);
      doc.fontSize(20)
         .font('Helvetica-Bold')
         .text('Overall SEO Score', 140, centerY - 20);

      doc.fontSize(14)
         .fillColor(colors.mutedForeground)
         .font('Helvetica')
         .text(performanceLevel.text, 140, centerY + 5);

      doc.fontSize(12)
         .text(analysis.url, 140, centerY + 25);

      doc.y = centerY + 70;

      // Category Cards Grid (matching web app design)
      doc.moveDown(1);
      const cardWidth = 160;
      const cardHeight = 120;
      const cardsPerRow = 3;
      const cardSpacing = 20;

      const categories = [
        { name: 'Technical SEO', score: analysis.technicalScore, icon: 'T', color: colors.blue, bgColor: colors.blueBg },
        { name: 'Performance', score: analysis.performanceScore, icon: 'P', color: colors.green, bgColor: colors.greenBg },
        { name: 'Accessibility', score: analysis.accessibilityScore, icon: 'A', color: colors.purple, bgColor: colors.purpleBg },
        { name: 'Keywords', score: analysis.keywordScore, icon: 'K', color: colors.orange, bgColor: colors.orangeBg },
        { name: 'Content Quality', score: analysis.contentScore, icon: 'C', color: colors.indigo, bgColor: colors.indigoBg }
      ];

      for (let i = 0; i < categories.length; i++) {
        const category = categories[i];
        const row = Math.floor(i / cardsPerRow);
        const col = i % cardsPerRow;
        const x = 40 + col * (cardWidth + cardSpacing);
        const y = doc.y + row * (cardHeight + cardSpacing);

        // Card background (matching web app rounded-xl border shadow-sm)
        createCard(doc, y, cardWidth, cardHeight);

        // Icon background (matching web app bg-blue-100 etc)
        doc.circle(x + 20, y + 25, 15)
           .fillColor(category.bgColor)
           .fill();

        // Icon (matching web app icon colors)
        doc.fillColor(category.color)
           .fontSize(14)
           .text(category.icon, x + 15, y + 20);

        // Category name
        doc.fillColor(colors.foreground)
           .fontSize(14)
           .font('Helvetica-Bold')
           .text(category.name, x + 45, y + 15, { width: cardWidth - 55 });

        // Score (matching web app styling)
        doc.fontSize(32)
           .fillColor(getScoreColor(category.score))
           .font('Helvetica-Bold')
           .text(`${category.score}`, x + 45, y + 35);

        doc.fontSize(16)
           .fillColor(colors.mutedForeground)
           .font('Helvetica')
           .text('/100', x + 85, y + 45);

        // Progress indicator (matching web app progress bars)
        const progressY = y + 75;
        const progressWidth = cardWidth - 25;
        const progressHeight = 4;
        const progressFill = (category.score / 100) * progressWidth;

        // Progress track (background)
        doc.rect(x + 12, progressY, progressWidth, progressHeight)
           .fillColor(colors.muted)
           .fill();

        // Progress fill
        doc.rect(x + 12, progressY, progressFill, progressHeight)
           .fillColor(getScoreColor(category.score))
           .fill();
      }

      doc.y += Math.ceil(categories.length / cardsPerRow) * (cardHeight + cardSpacing) + 20;

      // Detailed Analysis Sections
      const results = analysis.results as any;

      if (results) {
        try {
          // Technical SEO Analysis
          if (results.technical && Array.isArray(results.technical)) {
            createDetailedSection(doc, 'Technical SEO Analysis', '', results.technical);
          }

          // Performance Analysis  
          if (results.performance && Array.isArray(results.performance)) {
            createDetailedSection(doc, 'Performance Analysis', '', results.performance);
          }

          // Accessibility Analysis
          if (results.accessibility && Array.isArray(results.accessibility)) {
            createDetailedSection(doc, 'Accessibility Analysis', '', results.accessibility);
          }

          // Keywords Analysis (fixed data structure)
          if (results.keyword && typeof results.keyword === 'object') {
            // Convert keyword object to array format for consistency
            const keywordChecks = [
              {
                name: 'Meta Title',
                status: results.keyword.metaTitle?.present ? 'PASS' : 'FAIL',
                details: results.keyword.metaTitle?.present 
                  ? `Title length: ${results.keyword.metaTitle.length} characters`
                  : 'Missing meta title',
                priority: results.keyword.metaTitle?.present ? 'Excellent' : 'Critical',
                action: results.keyword.metaTitle?.present ? 'Perfect!' : 'Add Title'
              },
              {
                name: 'Meta Description',
                status: results.keyword.metaDescription?.present ? 'PASS' : 'FAIL',
                details: results.keyword.metaDescription?.present 
                  ? `Description length: ${results.keyword.metaDescription.length} characters`
                  : 'Missing meta description',
                priority: results.keyword.metaDescription?.present ? 'Excellent' : 'Critical',
                action: results.keyword.metaDescription?.present ? 'Perfect!' : 'Add Description'
              },
              {
                name: 'Heading Structure',
                status: results.keyword.headingStructure?.hierarchyValid ? 'PASS' : 'WARNING',
                details: `${results.keyword.headingStructure?.h1Count || 0} H1 tags found`,
                priority: results.keyword.headingStructure?.hierarchyValid ? 'Excellent' : 'Medium',
                action: results.keyword.headingStructure?.hierarchyValid ? 'Great!' : 'Fix Hierarchy'
              }
            ];
            createDetailedSection(doc, 'Keywords Analysis', '', keywordChecks);
          }

          // Content Quality Analysis (fixed data structure)
          if (results.content && typeof results.content === 'object') {
            // Convert content object to array format for consistency
            const contentChecks = [
              {
                name: 'Word Count',
                status: results.content.wordCount > 300 ? 'PASS' : 'WARNING',
                details: `Page contains ${results.content.wordCount} words`,
                priority: results.content.wordCount > 300 ? 'Excellent' : 'Medium',
                action: results.content.wordCount > 300 ? 'Great!' : 'Add Content'
              },
              {
                name: 'Image Alt Tags',
                status: results.content.imageAltTags?.percentage === 100 ? 'PASS' : 'WARNING',
                details: `${results.content.imageAltTags?.percentage || 0}% of images have alt tags`,
                priority: results.content.imageAltTags?.percentage === 100 ? 'Excellent' : 'Medium',
                action: results.content.imageAltTags?.percentage === 100 ? 'Perfect!' : 'Add Alt Tags'
              },
              {
                name: 'Structured Data',
                status: results.content.structuredData ? 'PASS' : 'WARNING',
                details: results.content.structuredData ? 'Structured data found' : 'No structured data detected',
                priority: results.content.structuredData ? 'Excellent' : 'Medium',
                action: results.content.structuredData ? 'Great!' : 'Add Schema'
              }
            ];
            createDetailedSection(doc, 'Content Quality Analysis', '', contentChecks);
          }
        } catch (sectionError) {
          // Continue with recommendations even if sections fail
        }
      }

      // Priority Recommendations Section (compact design)
      if (analysis.recommendations && Array.isArray(analysis.recommendations) && analysis.recommendations.length > 0) {
        if (doc.y > 600) {
          doc.addPage();
          doc.y = 40;
        }

        createSectionHeader(doc, 'Priority Recommendations');

        analysis.recommendations.slice(0, 5).forEach((rec: any, index: number) => {
          if (doc.y > 720) {
            doc.addPage();
            doc.y = 40;
          }

          const recY = doc.y;
          const recHeight = 50;

          // Recommendation card (matching web app style)
          createCard(doc, recY, doc.page.width - 80, recHeight);

          // Priority indicator (left border)
          doc.rect(40, recY, 4, recHeight)
             .fillColor(getPriorityColor(rec.priority))
             .fill();

          // Recommendation content
          doc.fillColor(colors.foreground)
             .fontSize(12)
             .font('Helvetica-Bold')
             .text(`${index + 1}. ${rec.title}`, 55, recY + 10, { width: 350 });

          // Priority and category badges
          createBadge(doc, doc.page.width - 170, recY + 8, rec.priority, 
                     getPriorityColor(rec.priority), 
                     getPriorityBgColor(rec.priority));

          createBadge(doc, doc.page.width - 110, recY + 8, rec.category || 'SEO', 
                     colors.primary, colors.background);

          // Description
          doc.fillColor(colors.mutedForeground)
             .fontSize(10)
             .font('Helvetica')
             .text(rec.description, 55, recY + 28, { width: doc.page.width - 140 });

          doc.y = recY + recHeight + 8;
        });
      }

      // Enhanced Footer
      addFooter(doc, analysis.url);

      doc.end();
    } catch (error) {
      reject(error);
    }
  });
}

function createCard(doc: InstanceType<typeof PDFDocument>, y: number, width: number, height: number) {
  // Card background with shadow (matching web app card styling)
  doc.rect(40, y, width, height)
     .fillColor(colors.card)
     .fill()
     .strokeColor(colors.border)
     .lineWidth(1)
     .stroke();

  // Subtle shadow effect
  doc.rect(42, y + 2, width, height)
     .fillColor(colors.shadow)
     .fillOpacity(0.05)
     .fill()
     .fillOpacity(1);
}

function createSectionHeader(doc: InstanceType<typeof PDFDocument>, title: string, _icon?: string) {
  ensureSpace(doc, 40);
  doc.fillColor(colors.primary)
     .fontSize(16)
     .font('Helvetica-Bold')
     .text(title, 40, doc.y, { width: doc.page.width - 80 });
  doc.moveDown(0.3);
  doc.moveTo(40, doc.y).lineTo(doc.page.width - 40, doc.y)
     .strokeColor(colors.border).lineWidth(1).stroke();
  doc.moveDown(0.4);
}

function createDetailedSection(doc: InstanceType<typeof PDFDocument>, title: string, _icon: string, checks: any[]) {
  createSectionHeader(doc, title);

  const passCount = checks.filter(c => c.status === 'PASS').length;
  const warningCount = checks.filter(c => c.status === 'WARNING').length;
  const failCount = checks.filter(c => c.status === 'FAIL').length;

  const statsY = doc.y;
  createBadge(doc, 40, statsY, `${checks.length} Total`, colors.mutedForeground, colors.muted);
  createBadge(doc, 110, statsY, `${passCount} Pass`, colors.green, colors.greenBg);
  createBadge(doc, 180, statsY, `${warningCount} Warning`, colors.orange, colors.orangeBg);
  createBadge(doc, 260, statsY, `${failCount} Fail`, colors.red, colors.redBg);
  doc.y = statsY + 25;

  const contentW = doc.page.width - 80;
  const textAreaWidth = contentW - 100;

  checks.forEach((check) => {
    const detailStr = (check.details || '').substring(0, 150);
    const impactStr = (check.whyItMatters || '').substring(0, 200);

    doc.fontSize(9).font('Helvetica');
    const detailH = doc.heightOfString(detailStr, { width: textAreaWidth });
    const nameH = 14;
    let rowH = nameH + detailH + 6;
    let impactH = 0;
    if (impactStr) {
      impactH = doc.heightOfString(impactStr, { width: contentW - 20 }) + 4;
      rowH += impactH;
    }
    rowH = Math.max(30, rowH);

    ensureSpace(doc, rowH + 4);
    const itemY = doc.y;

    doc.rect(40, itemY, contentW, rowH)
       .fillColor(colors.background).fill()
       .strokeColor(colors.border).lineWidth(0.5).stroke();

    doc.circle(55, itemY + 12, 4).fillColor(getStatusColor(check.status)).fill();

    doc.fillColor(colors.foreground).fontSize(10).font('Helvetica-Bold')
       .text(check.name || '', 68, itemY + 4, { width: textAreaWidth, lineBreak: false, ellipsis: true });

    const badgeX = doc.page.width - 120;
    createBadge(doc, badgeX, itemY + 4, check.status,
               getStatusColor(check.status), getStatusBgColor(check.status));

    doc.fillColor(colors.mutedForeground).fontSize(9).font('Helvetica')
       .text(detailStr, 68, itemY + nameH + 2, { width: textAreaWidth });

    if (impactStr) {
      const impactY = itemY + nameH + detailH + 6;
      doc.fillColor('#6b7280').fontSize(8).font('Helvetica-Oblique')
         .text(impactStr, 50, impactY, { width: contentW - 20 });
    }

    doc.y = itemY + rowH + 2;
  });
  doc.moveDown(0.5);
}

function createBadge(doc: InstanceType<typeof PDFDocument>, x: number, y: number, text: string, textColor: string, bgColor: string) {
  const padding = 6;
  doc.fontSize(8);
  const textWidth = doc.widthOfString(text);
  const badgeWidth = textWidth + padding * 2;

  // Badge background (rounded rectangle effect)
  doc.rect(x, y, badgeWidth, 16)
     .fillColor(bgColor)
     .fill();

  // Badge text
  doc.fillColor(textColor)
     .fontSize(8)
     .font('Helvetica-Bold')
     .text(text, x + padding, y + 4);
}

function getCheckCardHeight(check: any): number {
  let height = 50; // Base height
  if (check.action) height += 15;

  const guidance = getActionGuidance(check);
  if (guidance.action !== 'Great job! This check is passing.' && guidance.action !== 'Review and improve this aspect of your website.') {
    height += 30; // For guidance and resources
  }

  return height;
}

function getActionGuidance(check: any) {
  const guides = {
    "H1 Tags": {
      description: "H1 tags are crucial for SEO as they tell search engines what your page is about.",
      action: check.status === "PASS" ? "Perfect! Your page has exactly one H1 tag." : "Add a single, descriptive H1 tag to your page.",
      resources: ["https://moz.com/learn/seo/title-tag", "https://developers.google.com/web/fundamentals/design-and-ux/typography"]
    },
    "Meta Description": {
      description: "Meta descriptions appear in search results and influence click-through rates.",
      action: check.status === "PASS" ? "Great! Your meta description is properly set." : "Add a compelling meta description between 150-160 characters.",
      resources: ["https://moz.com/learn/seo/meta-description", "https://developers.google.com/search/docs/advanced/appearance/snippet"]
    },
    "Image Alt Tags": {
      description: "Alt tags help search engines understand your images and improve accessibility.",
      action: check.status === "PASS" ? "Excellent! Your images have proper alt tags." : "Add descriptive alt tags to all images.",
      resources: ["https://moz.com/learn/seo/alt-text", "https://www.w3.org/WAI/tutorials/images/"]
    },
    "Page Title": {
      description: "Page titles are one of the most important on-page SEO elements.",
      action: check.status === "PASS" ? "Excellent! Your page has a proper title." : "Add a descriptive, keyword-rich page title.",
      resources: ["https://moz.com/learn/seo/title-tag"]
    },
    "Robots.txt": {
      description: "Robots.txt file helps control search engine crawling behavior.",
      action: check.status === "PASS" ? "Perfect! Your robots.txt file is accessible." : "Create and configure a robots.txt file.",
      resources: ["https://developers.google.com/search/docs/advanced/robots/robots_txt"]
    }
  };

  return guides[check.name as keyof typeof guides] || {
    description: "This check helps improve your website's SEO performance.",
    action: check.status === "PASS" ? "Great job! This check is passing." : "Review and improve this aspect of your website.",
    resources: ["https://moz.com/learn/seo", "https://developers.google.com/search/docs"]
  };
}

function addFooter(doc: InstanceType<typeof PDFDocument>, url: string) {
  const footerY = doc.page.height - 40;

  // Simple footer line
  doc.moveTo(40, footerY)
     .lineTo(doc.page.width - 40, footerY)
     .strokeColor(colors.border)
     .lineWidth(1)
     .stroke();

  doc.fillColor(colors.mutedForeground)
     .fontSize(9)
     .font('Helvetica')
     .text(`SEO Analyzer Pro • ${url}`, 40, footerY + 10)
     .text(`Generated ${new Date().toLocaleDateString()}`, { align: 'right' });
}

function getPerformanceLevel(score: number) {
  if (score >= 90) return { text: 'Excellent', color: '#16a34a' };
  if (score >= 75) return { text: 'Good', color: '#059669' };
  if (score >= 60) return { text: 'Average', color: '#ca8a04' };
  if (score >= 40) return { text: 'Needs Improvement', color: '#ea580c' };
  return { text: 'Poor', color: '#dc2626' };
}

// Web App Color System (exact HSL to Hex conversion)
const colors = {
  // Primary colors
  primary: '#3b82f6',        // hsl(221.2, 83.2%, 53.3%)
  background: '#fafbff',     // hsl(210, 40%, 98%)
  card: '#ffffff',           // hsl(0, 0%, 100%)
  border: '#e2e8f0',         // hsl(214.3, 31.8%, 91.4%)
  foreground: '#0f172a',     // hsl(222.2, 84%, 4.9%)
  mutedForeground: '#64748b', // hsl(215.4, 16.3%, 46.9%)
  muted: '#f8fafc',          // hsl(210, 40%, 96%)
  shadow: '#000000',

  // Category colors (matching web app)
  blue: '#2563eb',           // Technical SEO
  blueBg: '#dbeafe',
  green: '#16a34a',          // Performance  
  greenBg: '#dcfce7',
  purple: '#9333ea',         // Accessibility
  purpleBg: '#f3e8ff',
  orange: '#ea580c',         // Keywords
  orangeBg: '#fed7aa',
  indigo: '#4f46e5',         // Content
  indigoBg: '#e0e7ff',

  // Status colors
  red: '#dc2626',
  redBg: '#fef2f2',
  yellow: '#ca8a04',
  yellowBg: '#fefce8'
};

function getScoreColor(score: number): string {
  if (score >= 80) return colors.green;
  if (score >= 60) return colors.yellow;
  if (score >= 40) return colors.orange;
  return colors.red;
}

function getStatusColor(status: string): string {
  switch (status) {
    case 'PASS': return colors.green;
    case 'WARNING': return colors.orange;
    case 'FAIL': return colors.red;
    default: return colors.mutedForeground;
  }
}

function getStatusBgColor(status: string): string {
  switch (status) {
    case 'PASS': return colors.greenBg;
    case 'WARNING': return colors.orangeBg;
    case 'FAIL': return colors.redBg;
    default: return colors.muted;
  }
}

function getPriorityColor(priority: string): string {
  switch (priority) {
    case 'Excellent': return colors.green;
    case 'Good': return colors.green;
    case 'Medium': return colors.yellow;
    case 'Critical': return colors.red;
    default: return colors.mutedForeground;
  }
}

function getPriorityBgColor(priority: string): string {
  switch (priority) {
    case 'Excellent': return colors.greenBg;
    case 'Good': return colors.greenBg;
    case 'Medium': return colors.yellowBg;
    case 'Critical': return colors.redBg;
    default: return colors.muted;
  }
}

interface MasterResult {
  url: string;
  seo: { data: any | null; error: string | null };
  ads: { data: any | null; error: string | null };
  aeo: { data: any | null; error: string | null };
  geo: { data: any | null; error: string | null };
  brokenLinks: { data: any | null; error: string | null };
  imageOptimization: { data: any | null; error: string | null };
  internalLinking: { data: any | null; error: string | null };
  sitemapValidator: { data: any | null; error: string | null };
}

function ensureSpace(doc: InstanceType<typeof PDFDocument>, needed: number) {
  if (doc.y + needed > doc.page.height - 60) {
    doc.addPage();
    doc.y = 40;
  }
}

function addMasterFooter(doc: InstanceType<typeof PDFDocument>, _url: string) {
  const range = doc.bufferedPageRange();
  const totalPages = range.count;
  for (let i = range.start; i < range.start + totalPages; i++) {
    doc.switchToPage(i);
    const footerY = doc.page.height - 35;
    doc.moveTo(40, footerY - 5)
       .lineTo(doc.page.width - 40, footerY - 5)
       .strokeColor(colors.border)
       .lineWidth(0.5)
       .stroke();
    doc.y = footerY;
    doc.fillColor(colors.mutedForeground)
       .fontSize(8)
       .font('Helvetica')
       .text(`SEO Analyzer Pro`, 40, footerY, { lineBreak: false, continued: false });
    doc.y = footerY;
    doc.fillColor(colors.mutedForeground)
       .fontSize(8)
       .font('Helvetica')
       .text(`Page ${i + 1} of ${totalPages}`, doc.page.width - 130, footerY, { lineBreak: false, continued: false });
    doc.y = footerY;
  }
  doc.switchToPage(range.start + totalPages - 1);
  doc.y = 50;
}

function drawScoreBox(doc: InstanceType<typeof PDFDocument>, x: number, y: number, width: number, label: string, score: number) {
  doc.rect(x, y, width, 50)
     .fillColor(colors.card)
     .fill()
     .strokeColor(colors.border)
     .lineWidth(0.5)
     .stroke();
  doc.fillColor(getScoreColor(score))
     .fontSize(22)
     .font('Helvetica-Bold')
     .text(`${score}`, x + 8, y + 6, { width: width - 16 });
  doc.fillColor(colors.mutedForeground)
     .fontSize(8)
     .font('Helvetica')
     .text(label, x + 8, y + 32, { width: width - 16 });
}

function drawScoreCircle(doc: InstanceType<typeof PDFDocument>, cx: number, cy: number, radius: number, score: number, label: string, ringColor?: string) {
  const color = ringColor || getScoreColor(score);
  const startAngle = -Math.PI / 2;
  const endAngle = startAngle + (score / 100) * 2 * Math.PI;

  doc.save();
  doc.circle(cx, cy, radius)
     .lineWidth(radius > 20 ? 6 : 4)
     .strokeColor(colors.border)
     .stroke();

  if (score > 0) {
    doc.save();
    doc.lineWidth(radius > 20 ? 6 : 4);
    doc.strokeColor(color);
    const segments = Math.max(1, Math.round((score / 100) * 60));
    const angleStep = (endAngle - startAngle) / segments;
    for (let i = 0; i < segments; i++) {
      const a1 = startAngle + i * angleStep;
      const a2 = startAngle + (i + 1) * angleStep;
      const x1 = cx + radius * Math.cos(a1);
      const y1 = cy + radius * Math.sin(a1);
      const x2 = cx + radius * Math.cos(a2);
      const y2 = cy + radius * Math.sin(a2);
      doc.moveTo(x1, y1).lineTo(x2, y2).stroke();
    }
    doc.restore();
  }

  const fontSize = radius > 20 ? 16 : 11;
  doc.fillColor(colors.foreground)
     .fontSize(fontSize)
     .font('Helvetica-Bold');
  const scoreStr = `${score}`;
  const textW = doc.widthOfString(scoreStr);
  doc.text(scoreStr, cx - textW / 2, cy - fontSize / 2 - 1, { lineBreak: false });

  if (label) {
    doc.fillColor(colors.mutedForeground)
       .fontSize(radius > 20 ? 8 : 7)
       .font('Helvetica');
    const labelW = doc.widthOfString(label);
    const maxLabelW = radius * 2 + 10;
    if (labelW > maxLabelW) {
      doc.text(label, cx - maxLabelW / 2, cy + radius + 6, { width: maxLabelW, align: 'center' });
    } else {
      doc.text(label, cx - labelW / 2, cy + radius + 6, { lineBreak: false });
    }
  }
  doc.restore();
}

function drawRecommendations(doc: InstanceType<typeof PDFDocument>, recommendations: any[]) {
  if (!recommendations || !Array.isArray(recommendations) || recommendations.length === 0) return;
  ensureSpace(doc, 50);
  doc.fillColor(colors.foreground).fontSize(11).font('Helvetica-Bold').text('Recommendations', 50, doc.y);
  doc.moveDown(0.3);
  recommendations.slice(0, 5).forEach((rec: any, i: number) => {
    const text = typeof rec === 'string' ? rec : (rec.title || rec.description || JSON.stringify(rec));
    const cleanText = text.substring(0, 200);
    const priority = typeof rec === 'object' && rec.priority ? rec.priority : '';
    doc.fontSize(9).font('Helvetica');
    const textH = doc.heightOfString(`${i + 1}. ${cleanText}`, { width: doc.page.width - 150 });
    const rowH = Math.max(22, textH + 10);
    ensureSpace(doc, rowH + 4);
    const y = doc.y;
    doc.rect(50, y, doc.page.width - 100, rowH)
       .fillColor(i % 2 === 0 ? colors.background : colors.card)
       .fill();
    if (priority) {
      doc.rect(50, y, 3, rowH).fillColor(getPriorityColor(priority)).fill();
    }
    doc.fillColor(colors.foreground).fontSize(9).font('Helvetica')
       .text(`${i + 1}. ${cleanText}`, 58, y + 5, { width: doc.page.width - 150, height: rowH - 6 });
    if (priority) {
      createBadge(doc, doc.page.width - 120, y + 5, priority, getPriorityColor(priority), getPriorityBgColor(priority));
    }
    doc.y = y + rowH + 2;
  });
  doc.moveDown(0.5);
}

export async function generateMasterPdfReport(data: MasterResult, tier: 'free' | 'basic' | 'pro' = 'pro'): Promise<Buffer> {
  return new Promise((resolve, reject) => {
    try {
      const doc = new PDFDocument({
        margin: 30,
        size: 'A4',
        bufferPages: true,
        info: {
          Title: `Master SEO Report - ${data.url}`,
          Author: 'SEO Analyzer Pro',
          Subject: 'Comprehensive Website Analysis',
          Keywords: 'SEO, AEO, Ads, Analysis, Optimization'
        }
      });
      const buffers: Buffer[] = [];
      doc.on('data', (chunk: Buffer) => buffers.push(chunk));
      doc.on('end', () => resolve(Buffer.concat(buffers)));
      doc.on('error', reject);

      const pageWidth = doc.page.width;
      const contentWidth = pageWidth - 80;

      // ── HEADER ──
      const headerHeight = 80;
      doc.rect(0, 0, pageWidth, headerHeight).fill(colors.primary);
      doc.fillColor('white').fontSize(24).font('Helvetica-Bold')
         .text('SEO Analyzer Pro', 50, 20);
      doc.fontSize(12).font('Helvetica')
         .text(`Master Analysis Report for ${data.url}`, 50, 48);
      doc.fontSize(10)
         .text(`Generated ${new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' })}`, pageWidth - 200, 48);
      doc.fillColor(colors.foreground);
      doc.y = headerHeight + 20;

      // ── OVERALL SCORE DASHBOARD ──
      const toolColors: Record<string, string> = {
        'SEO': '#3b82f6', 'Ads': '#f59e0b', 'AEO': '#8b5cf6', 'GEO': '#14b8a6',
        'Links': '#ef4444', 'Images': '#10b981', 'Int. Links': '#06b6d4', 'Sitemap': '#ec4899'
      };
      const scores: { label: string; score: number; color: string }[] = [];
      if (data.seo?.data) scores.push({ label: 'SEO', score: data.seo.data.overallScore ?? 0, color: toolColors['SEO'] });
      if (data.ads?.data) scores.push({ label: 'Ads', score: data.ads.data.results?.score ?? 0, color: toolColors['Ads'] });
      if (data.aeo?.data) scores.push({ label: 'AEO', score: data.aeo.data.results?.score ?? 0, color: toolColors['AEO'] });
      if (data.geo?.data) scores.push({ label: 'GEO', score: data.geo.data.results?.score ?? 0, color: toolColors['GEO'] });
      if (data.brokenLinks?.data) scores.push({ label: 'Links', score: data.brokenLinks.data.score ?? 0, color: toolColors['Links'] });
      if (data.imageOptimization?.data) scores.push({ label: 'Images', score: data.imageOptimization.data.score ?? 0, color: toolColors['Images'] });
      if (data.internalLinking?.data) scores.push({ label: 'Int. Links', score: data.internalLinking.data.score ?? 0, color: toolColors['Int. Links'] });
      if (data.sitemapValidator?.data) scores.push({ label: 'Sitemap', score: data.sitemapValidator.data.score ?? 0, color: toolColors['Sitemap'] });

      const overallAvg = scores.length > 0 ? Math.round(scores.reduce((s, c) => s + c.score, 0) / scores.length) : 0;

      createSectionHeader(doc, 'Overall Score Dashboard');
      const dashY = doc.y;
      const overallR = 32;
      const overallCx = 40 + overallR + 10;
      const overallCy = dashY + overallR + 5;
      drawScoreCircle(doc, overallCx, overallCy, overallR, overallAvg, 'Overall');

      if (scores.length > 0) {
        const smallR = 22;
        const circleSpacing = (contentWidth - (overallR * 2 + 30)) / scores.length;
        const startX = overallCx + overallR + 30 + smallR;
        scores.forEach((s, i) => {
          const cx = startX + i * circleSpacing;
          drawScoreCircle(doc, cx, overallCy, smallR, s.score, s.label, s.color);
        });
      }
      doc.y = overallCy + overallR + 28;

      // ── FREE TIER: show top 3 critical issues + upgrade CTA ──
      if (tier === 'free') {
        const criticalIssues: { tool: string; issue: string }[] = [];
        const collectFails = (toolName: string, checks: any[]) => {
          if (!checks) return;
          checks.forEach((c: any) => {
            if (c.status === 'fail' || c.status === 'error' || c.status === 'warning') {
              criticalIssues.push({ tool: toolName, issue: c.name || c.message || 'Issue detected' });
            }
          });
        };
        if (data.seo?.data?.results?.technical) collectFails('SEO', data.seo.data.results.technical);
        if (data.ads?.data?.results?.checks) collectFails('Ads', data.ads.data.results.checks);
        if (data.aeo?.data?.results?.checks) collectFails('AEO', data.aeo.data.results.checks);
        if (data.geo?.data?.results?.checks) collectFails('GEO', data.geo.data.results.checks);

        ensureSpace(doc, 100);
        createSectionHeader(doc, 'Top Critical Issues');
        const topIssues = criticalIssues.slice(0, 3);
        if (topIssues.length === 0) {
          doc.fillColor(colors.green).fontSize(10).font('Helvetica')
             .text('No critical issues found. Your site is performing well!', 50, doc.y);
          doc.moveDown(1);
        } else {
          topIssues.forEach((issue, i) => {
            ensureSpace(doc, 20);
            doc.fillColor(colors.red).fontSize(10).font('Helvetica-Bold')
               .text(`${i + 1}. [${issue.tool}] ${issue.issue}`, 50, doc.y, { width: contentWidth - 20 });
            doc.moveDown(0.5);
          });
        }
        doc.moveDown(1);

        ensureSpace(doc, 120);
        const ctaY = doc.y;
        doc.rect(40, ctaY, contentWidth, 90).fill('#f0f4ff');
        doc.fillColor(colors.primary).fontSize(16).font('Helvetica-Bold')
           .text('Unlock Your Full Report', 60, ctaY + 12, { width: contentWidth - 40 });
        doc.fillColor(colors.foreground).fontSize(10).font('Helvetica')
           .text('This is a preview report. Upgrade to see full technical details, fix instructions, and expert recommendations.', 60, ctaY + 35, { width: contentWidth - 40 });
        doc.fillColor(colors.primary).fontSize(11).font('Helvetica-Bold')
           .text('Basic Report: €29  •  Pro Report + Consultation: €249', 60, ctaY + 60, { width: contentWidth - 40 });
        doc.y = ctaY + 100;

        addMasterFooter(doc, data.url);
        doc.end();
        return;
      }

      const showRecommendations = tier === 'pro';

      // ── SEO AUDIT SECTION ──
      if (data.seo?.data) {
        ensureSpace(doc, 200);
        createSectionHeader(doc, 'SEO Audit');
        const seo = data.seo.data;

        const catScores = [
          { name: 'Technical', score: seo.technicalScore ?? 0 },
          { name: 'Performance', score: seo.performanceScore ?? 0 },
          { name: 'Accessibility', score: seo.accessibilityScore ?? 0 },
          { name: 'Keywords', score: seo.keywordScore ?? 0 },
          { name: 'Content', score: seo.contentScore ?? 0 }
        ];
        const catR = 20;
        const catSpacing = contentWidth / 5;
        const catCy = doc.y + catR + 5;
        catScores.forEach((c, i) => {
          drawScoreCircle(doc, 40 + catSpacing / 2 + i * catSpacing, catCy, catR, c.score, c.name);
        });
        doc.y = catCy + catR + 22;

        if (seo.results?.technical && Array.isArray(seo.results.technical)) {
          createDetailedSection(doc, 'Technical Checks', '', seo.results.technical);
        }
        if (showRecommendations) drawRecommendations(doc, seo.recommendations);
      }

      // ── GOOGLE ADS SECTION ──
      if (data.ads?.data) {
        ensureSpace(doc, 150);
        createSectionHeader(doc, 'Google Ads Landing Page');
        const ads = data.ads.data;
        const r = ads.results || {};

        const adsInfoLines: string[] = [`Score: ${r.score ?? 'N/A'}/100`];
        if (r.rating) adsInfoLines.push(`Rating: ${r.rating}`);
        if (r.ttfb !== undefined) adsInfoLines.push(`TTFB: ${typeof r.ttfb === 'object' ? (r.ttfb.cleanUrl ?? 'N/A') : r.ttfb}ms`);
        if (r.cdn !== undefined) adsInfoLines.push(`CDN: ${typeof r.cdn === 'object' ? (r.cdn.detected ? 'Yes' : 'No') : (r.cdn ? 'Yes' : 'No')}`);
        if (r.redirects !== undefined) adsInfoLines.push(`Redirects: ${typeof r.redirects === 'object' ? (r.redirects.hops ?? 0) : r.redirects}`);

        doc.fillColor(colors.foreground).fontSize(11).font('Helvetica-Bold')
           .text(adsInfoLines[0], 50, doc.y);
        doc.fillColor(colors.mutedForeground).fontSize(10).font('Helvetica');
        adsInfoLines.slice(1).forEach(line => {
          ensureSpace(doc, 16);
          doc.text(line, 50, doc.y);
        });
        doc.moveDown(0.5);

        if (r.checks && Array.isArray(r.checks)) {
          createDetailedSection(doc, 'Ads Checks', '', r.checks);
        }
        if (showRecommendations) drawRecommendations(doc, ads.recommendations);
      }

      // ── AEO SECTION ──
      if (data.aeo?.data) {
        ensureSpace(doc, 180);
        createSectionHeader(doc, 'Answer Engine Optimization (AEO)');
        const aeo = data.aeo.data;
        const ar = aeo.results || {};

        const aeoInfoY = doc.y;
        doc.fillColor(colors.foreground).fontSize(11).font('Helvetica-Bold')
           .text(`Score: ${ar.score ?? 'N/A'}/100  •  Rating: ${ar.rating ?? 'N/A'}`, 50, aeoInfoY);
        doc.y = aeoInfoY + 18;

        const aeoCats = [
          { name: 'Structured Data', score: ar.structuredDataScore ?? 0 },
          { name: 'Content Format', score: ar.contentFormatScore ?? 0 },
          { name: 'Authority', score: ar.authorityScore ?? 0 },
          { name: 'Semantic', score: ar.semanticScore ?? 0 },
          { name: 'AI Access', score: ar.aiAccessibilityScore ?? 0 }
        ];
        const aeoCatR = 20;
        const aeoCatSpacing = contentWidth / 5;
        const aeoCatCy = doc.y + aeoCatR + 5;
        aeoCats.forEach((c, i) => {
          drawScoreCircle(doc, 40 + aeoCatSpacing / 2 + i * aeoCatSpacing, aeoCatCy, aeoCatR, c.score, c.name);
        });
        doc.y = aeoCatCy + aeoCatR + 22;

        if (ar.citationLikelihood) {
          doc.fillColor(colors.foreground).fontSize(10).font('Helvetica')
             .text(`Citation Likelihood: ${ar.citationLikelihood.score ?? 'N/A'}/100 (${ar.citationLikelihood.rating ?? ''})`, 50, doc.y);
          doc.moveDown(0.5);
        }

        if (ar.checks && Array.isArray(ar.checks)) {
          const mappedChecks = ar.checks.map((c: any) => ({
            name: c.name,
            status: c.status,
            details: (c.details || '').substring(0, 150),
            whyItMatters: c.impact || '',
          }));
          createDetailedSection(doc, 'AEO Checks', '', mappedChecks);
        }
        if (showRecommendations) drawRecommendations(doc, aeo.recommendations);
      }

      // ── GEO SECTION ──
      if (data.geo?.data) {
        ensureSpace(doc, 180);
        createSectionHeader(doc, 'Generative Engine Optimization (GEO)');
        const geo = data.geo.data;
        const gr = geo.results || {};

        const geoInfoY = doc.y;
        doc.fillColor(colors.foreground).fontSize(11).font('Helvetica-Bold')
           .text(`Score: ${gr.score ?? 'N/A'}/100  •  Rating: ${gr.rating ?? 'N/A'}  •  Generative Readiness: ${gr.generativeReadinessScore ?? 'N/A'}/100`, 50, geoInfoY, { width: contentWidth - 20 });
        doc.y = geoInfoY + 18;

        const geoCats = [
          { name: 'Source Auth.', score: gr.sourceAuthorityScore ?? 0 },
          { name: 'Fluency', score: gr.contentFluencyScore ?? 0 },
          { name: 'Unique Value', score: gr.uniqueValueScore ?? 0 },
          { name: 'Entity Opt.', score: gr.entityOptimizationScore ?? 0 },
          { name: 'Multi-Format', score: gr.multiFormatScore ?? 0 }
        ];
        const geoCatR = 20;
        const geoCatSpacing = contentWidth / 5;
        const geoCatCy = doc.y + geoCatR + 5;
        geoCats.forEach((c, i) => {
          drawScoreCircle(doc, 40 + geoCatSpacing / 2 + i * geoCatSpacing, geoCatCy, geoCatR, c.score, c.name);
        });
        doc.y = geoCatCy + geoCatR + 22;

        if (gr.checks && Array.isArray(gr.checks)) {
          const mappedChecks = gr.checks.map((c: any) => ({
            name: c.name,
            status: c.status,
            details: (c.details || '').substring(0, 150),
            whyItMatters: c.recommendation || '',
          }));
          createDetailedSection(doc, 'GEO Checks', '', mappedChecks);
        }
        if (showRecommendations) drawRecommendations(doc, geo.recommendations);
      }

      // ── BROKEN LINKS SECTION ──
      if (data.brokenLinks?.data) {
        ensureSpace(doc, 120);
        createSectionHeader(doc, 'Broken Links');
        const bl = data.brokenLinks.data;

        const blY = doc.y;
        const statItems = [
          { label: 'Total', value: bl.totalLinks ?? 0 },
          { label: 'Working', value: bl.workingLinks ?? 0 },
          { label: 'Broken', value: bl.brokenLinks ?? 0 },
          { label: 'Redirects', value: bl.redirectLinks ?? 0 },
          { label: 'Score', value: bl.score ?? 0 }
        ];
        const sW = (contentWidth) / statItems.length;
        statItems.forEach((s, i) => {
          const sx = 40 + i * sW;
          doc.fillColor(colors.foreground).fontSize(18).font('Helvetica-Bold')
             .text(`${s.value}`, sx, blY, { width: sW });
          doc.fillColor(colors.mutedForeground).fontSize(8).font('Helvetica')
             .text(s.label, sx, blY + 22, { width: sW });
        });
        doc.y = blY + 40;

        const broken = bl.links?.filter((l: any) => l.status === 'broken') || bl.brokenLinksList || [];
        if (broken.length > 0) {
          ensureSpace(doc, 40);
          doc.fillColor(colors.foreground).fontSize(10).font('Helvetica-Bold')
             .text('Broken Links Found:', 50, doc.y);
          doc.moveDown(0.3);
          broken.slice(0, 20).forEach((link: any) => {
            ensureSpace(doc, 16);
            const url = typeof link === 'string' ? link : (link.url || link.href || '');
            const code = link.statusCode || link.code || '';
            const linkText = `• ${url}${code ? ` (${code})` : ''}`.substring(0, 120);
            doc.fillColor(colors.red).fontSize(8).font('Helvetica')
               .text(linkText, 55, doc.y, { width: contentWidth - 30, height: 14 });
            doc.moveDown(0.2);
          });
        }
        doc.moveDown(0.5);
        if (showRecommendations) drawRecommendations(doc, bl.recommendations);
      }

      // ── IMAGE OPTIMIZATION SECTION ──
      if (data.imageOptimization?.data) {
        ensureSpace(doc, 150);
        createSectionHeader(doc, 'Image Optimization');
        const img = data.imageOptimization.data;

        const imgStats = [
          { label: 'Score', value: img.score ?? 0 },
          { label: 'Total Images', value: img.totalImages ?? 0 },
          { label: 'With Alt Text', value: img.withAltText ?? 0 },
          { label: 'Without Alt', value: img.withoutAltText ?? 0 },
          { label: 'Modern Format', value: img.modernFormatCount ?? 0 }
        ];
        const imgY = doc.y;
        const imgW = contentWidth / imgStats.length;
        imgStats.forEach((s, i) => {
          const sx = 40 + i * imgW;
          doc.fillColor(colors.foreground).fontSize(18).font('Helvetica-Bold')
             .text(`${s.value}`, sx, imgY, { width: imgW });
          doc.fillColor(colors.mutedForeground).fontSize(8).font('Helvetica')
             .text(s.label, sx, imgY + 22, { width: imgW });
        });
        doc.y = imgY + 45;
        if (showRecommendations) drawRecommendations(doc, img.recommendations);
      }

      // ── INTERNAL LINKING SECTION ──
      if (data.internalLinking?.data) {
        ensureSpace(doc, 120);
        createSectionHeader(doc, 'Internal Linking');
        const il = data.internalLinking.data;

        const ilStats = [
          { label: 'Score', value: il.score ?? 0 },
          { label: 'Total Links', value: il.totalLinks ?? 0 },
          { label: 'Unique Links', value: il.uniqueLinks ?? 0 },
          { label: 'Descriptive', value: il.descriptiveAnchors ?? 0 },
          { label: 'Generic', value: il.genericAnchors ?? 0 }
        ];
        const ilY = doc.y;
        const ilW = contentWidth / ilStats.length;
        ilStats.forEach((s, i) => {
          const sx = 40 + i * ilW;
          doc.fillColor(colors.foreground).fontSize(18).font('Helvetica-Bold')
             .text(`${s.value}`, sx, ilY, { width: ilW });
          doc.fillColor(colors.mutedForeground).fontSize(8).font('Helvetica')
             .text(s.label, sx, ilY + 22, { width: ilW });
        });
        doc.y = ilY + 45;
        if (showRecommendations) drawRecommendations(doc, il.recommendations);
      }

      // ── SITEMAP & ROBOTS.TXT SECTION ──
      if (data.sitemapValidator?.data) {
        ensureSpace(doc, 120);
        createSectionHeader(doc, 'Sitemap & Robots.txt');
        const sm = data.sitemapValidator.data;

        const smY = doc.y;
        doc.fillColor(colors.foreground).fontSize(10).font('Helvetica');
        let sy = smY;
        const robotsStatus = sm.robotsTxt?.exists ?? sm.hasRobotsTxt;
        const sitemapStatus = sm.sitemap?.exists ?? sm.hasSitemap;
        doc.text(`Robots.txt: ${robotsStatus ? 'Found' : 'Not Found'}`, 50, sy); sy += 16;
        doc.text(`Sitemap: ${sitemapStatus ? 'Found' : 'Not Found'}`, 50, sy); sy += 16;
        if (sm.urlCount !== undefined) { doc.text(`URLs in Sitemap: ${sm.urlCount}`, 50, sy); sy += 16; }
        if (sm.sitemap?.urlCount !== undefined) { doc.text(`URLs in Sitemap: ${sm.sitemap.urlCount}`, 50, sy); sy += 16; }
        doc.fillColor(colors.foreground).fontSize(18).font('Helvetica-Bold')
           .text(`${sm.score ?? 0}`, 400, smY, { width: 80 });
        doc.fillColor(colors.mutedForeground).fontSize(8).font('Helvetica')
           .text('Score', 400, smY + 22, { width: 80 });
        doc.y = sy + 5;

        if (sm.issues && Array.isArray(sm.issues) && sm.issues.length > 0) {
          ensureSpace(doc, 30);
          doc.fillColor(colors.foreground).fontSize(10).font('Helvetica-Bold')
             .text('Issues:', 50, doc.y);
          doc.moveDown(0.2);
          sm.issues.slice(0, 10).forEach((issue: any) => {
            ensureSpace(doc, 14);
            const text = typeof issue === 'string' ? issue : (issue.message || issue.description || JSON.stringify(issue));
            const issueText = `• ${text}`.substring(0, 120);
            doc.fillColor(colors.orange).fontSize(8).font('Helvetica')
               .text(issueText, 55, doc.y, { width: contentWidth - 30, height: 14 });
            doc.moveDown(0.2);
          });
        }
        doc.moveDown(0.5);
        if (showRecommendations) drawRecommendations(doc, sm.recommendations);
      }

      // ── FOOTER on every page ──
      addMasterFooter(doc, data.url);

      doc.end();
    } catch (error) {
      reject(error);
    }
  });
}

