import { useState, useEffect, forwardRef } from "react";
import { SeoAnalysis, TechnicalSeoCheck } from "@shared/schema";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { 
  Settings, 
  Search, 
  FileText, 
  Gauge, 
  Shield,
  CheckCircle,
  XCircle,
  AlertTriangle,
  Info,
  ExternalLink
} from "lucide-react";
import { Dialog, DialogContent, DialogDescription, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";

interface DetailedAnalysisProps {
  analysis: SeoAnalysis;
  activeTab?: TabType;
  onTabChange?: (tab: TabType) => void;
}

type TabType = "technical" | "keywords" | "content" | "performance" | "accessibility";

const DetailedAnalysis = forwardRef<HTMLDivElement, DetailedAnalysisProps>(function DetailedAnalysis({ analysis, activeTab: controlledTab, onTabChange }, ref) {
  const [internalTab, setInternalTab] = useState<TabType>("technical");
  const activeTab = controlledTab ?? internalTab;

  const handleTabChange = (tab: TabType) => {
    setInternalTab(tab);
    onTabChange?.(tab);
  };
  const [selectedCheck, setSelectedCheck] = useState<any>(null);

  const getActionGuidance = (check: any) => {
    const guides = {
      "H1 Tags": {
        description: "H1 tags are crucial for SEO as they tell search engines what your page is about.",
        action: check.status === "PASS" ? "Perfect! Your page has exactly one H1 tag." : "Add a single, descriptive H1 tag to your page.",
        resources: ["https://moz.com/learn/seo/title-tag", "https://developers.google.com/web/fundamentals/design-and-ux/typography"]
      },
      "Meta Description": {
        description: "Meta descriptions appear in search results and influence click-through rates.",
