                  {keyword.metaTitle?.present ? "Yes" : "No"}
                </Badge>
              </div>
              <div className="flex justify-between">
                <span>Length:</span>
                <span>{keyword.metaTitle?.length || 0} characters</span>
              </div>
              <div className="flex justify-between">
                <span>Optimized:</span>
                <Badge variant={keyword.metaTitle?.optimized ? "default" : "secondary"}>
                  {keyword.metaTitle?.optimized ? "Yes" : "No"}
                </Badge>
              </div>
            </div>
          </Card>

          <Card className="p-4">
            <h4 className="font-semibold mb-3">Meta Description</h4>
            <div className="space-y-2">
              <div className="flex justify-between">
                <span>Present:</span>
                <Badge variant={keyword.metaDescription?.present ? "default" : "destructive"}>
                  {keyword.metaDescription?.present ? "Yes" : "No"}
                </Badge>
              </div>
              <div className="flex justify-between">
                <span>Length:</span>
                <span>{keyword.metaDescription?.length || 0} characters</span>
              </div>
              <div className="flex justify-between">
                <span>Optimized:</span>
                <Badge variant={keyword.metaDescription?.optimized ? "default" : "secondary"}>
                  {keyword.metaDescription?.optimized ? "Yes" : "No"}
                </Badge>
              </div>
            </div>
          </Card>
        </div>

        <Card className="p-4">
          <h4 className="font-semibold mb-3">Top Keywords</h4>
          <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-2">
            {keyword.keywordDensity && Object.entries(keyword.keywordDensity).map(([word, density]: [string, any]) => (
              <div key={word} className="flex justify-between items-center p-2 bg-muted rounded">
                <span className="text-sm">{word}</span>
                <span className="text-sm font-medium">{density}%</span>
              </div>
            ))}
          </div>
        </Card>
      </div>
