}

function OverallDashboard({ data, onDownloadPdf, sessionId, paidTier, onTierChange }: { data: MasterResult; onDownloadPdf: (tier?: 'free' | 'basic' | 'pro') => void; sessionId?: string; paidTier: string; onTierChange: (tier: string) => void }) {
  const scores: { label: string; score: number; icon: any; color: string }[] = [];

  if (data.seo.data) scores.push({ label: "SEO", score: data.seo.data.overallScore, icon: Search, color: "#3b82f6" });
  if (data.ads.data) {
    const adsResults = data.ads.data.results as AdsAnalysisResults;
    scores.push({ label: "Ads LP", score: adsResults.score, icon: Zap, color: "#f59e0b" });
  }
  if (data.aeo.data) {
    const aeoResults = data.aeo.data.results as AeoAnalysisResults;
    scores.push({ label: "AEO", score: aeoResults.score, icon: Brain, color: "#8b5cf6" });
  }
  if (data.geo.data) {
    const geoResults = data.geo.data.results as GeoAnalysisResults;
    scores.push({ label: "GEO", score: geoResults.score, icon: Atom, color: "#14b8a6" });
  }
  if (data.brokenLinks.data) scores.push({ label: "Links", score: data.brokenLinks.data.score, icon: LinkIcon, color: "#ef4444" });
  if (data.imageOptimization.data) scores.push({ label: "Images", score: data.imageOptimization.data.score, icon: ImageIcon, color: "#10b981" });
  if (data.internalLinking.data) scores.push({ label: "Int. Links", score: data.internalLinking.data.score, icon: Network, color: "#06b6d4" });
  if (data.sitemapValidator.data) scores.push({ label: "Sitemap", score: data.sitemapValidator.data.score, icon: FileText, color: "#ec4899" });

  const avgScore = scores.length > 0 ? Math.round(scores.reduce((s, x) => s + x.score, 0) / scores.length) : 0;
  const overallColor = avgScore >= 80 ? "#10b981" : avgScore >= 50 ? "#f59e0b" : "#ef4444";
  const overallLabel = avgScore >= 80 ? "Excellent" : avgScore >= 60 ? "Good" : avgScore >= 40 ? "Needs Work" : "Critical";

  return (
    <Card className="mb-8" data-testid="master-overview">
      <CardContent className="pt-6">
        <div className="flex flex-col md:flex-row items-center gap-8">
