          </div>
          <div className="flex-1">
            <div className="flex flex-wrap justify-center gap-4">
              {scores.map((s) => (
                <ScoreCircle key={s.label} score={s.score} label={s.label} color={s.color} />
              ))}
            </div>
          </div>
        </div>
        <div className="mt-6 space-y-4">
          <p className="text-sm text-muted-foreground text-center">
            Comprehensive analysis of <span className="font-medium text-foreground">{data.url}</span> across {scores.length} tools
          </p>
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
            <Card className="border-green-200 dark:border-green-800 bg-green-50 dark:bg-green-950/30">
              <CardContent className="p-4 text-center">
                <div className="text-lg font-bold text-green-600">Free</div>
                <p className="text-xs text-muted-foreground mt-1">Overall scores + 3 critical issues</p>
                <Button onClick={() => onDownloadPdf('free')} size="sm" variant="outline" className="mt-3 w-full border-green-300 text-green-700 hover:bg-green-100">
                  <Mail className="w-4 h-4 mr-1" />
                  Get Free Report
                </Button>
              </CardContent>
            </Card>
            <Card className="border-blue-200 dark:border-blue-800 bg-blue-50 dark:bg-blue-950/30">
              <CardContent className="p-4 text-center">
                <div className="text-lg font-bold text-blue-600">€29</div>
                <p className="text-xs text-muted-foreground mt-1">Full technical breakdown</p>
                <Button onClick={() => onDownloadPdf('basic')} size="sm" className="mt-3 w-full bg-blue-600 hover:bg-blue-700">
                  <CreditCard className="w-4 h-4 mr-1" />
                  Basic Report
                </Button>
              </CardContent>
            </Card>
            <Card className="border-purple-200 dark:border-purple-800 bg-purple-50 dark:bg-purple-950/30 ring-2 ring-purple-400">
              <CardContent className="p-4 text-center">
                <div className="flex items-center justify-center gap-1">
                  <Crown className="w-4 h-4 text-purple-500" />
                  <div className="text-lg font-bold text-purple-600">€249</div>
                </div>
                <p className="text-xs text-muted-foreground mt-1">Full report + 30-min consultation</p>
                <Button onClick={() => onDownloadPdf('pro')} size="sm" className="mt-3 w-full bg-purple-600 hover:bg-purple-700">
                  <Star className="w-4 h-4 mr-1" />
                  Pro Report
                </Button>
              </CardContent>
            </Card>
          </div>
          <div className="mt-4 flex items-center justify-center gap-2 p-3 bg-amber-50 dark:bg-amber-950/30 rounded-lg border border-amber-200 dark:border-amber-800 border-dashed">
            <span className="text-xs font-medium text-amber-700 dark:text-amber-300">Dev Preview:</span>
            <select
              value={paidTier}
              onChange={(e) => onTierChange(e.target.value)}
              className="text-xs border border-amber-300 dark:border-amber-700 rounded px-2 py-1 bg-white dark:bg-amber-950 text-amber-800 dark:text-amber-200 font-medium"
            >
              <option value="free">Free Tier</option>
