          </Button>
          <Button size="sm" onClick={onUpgrade} className="bg-purple-600 hover:bg-purple-700">
            <Crown className="w-3 h-3 mr-1" />€249 Pro
          </Button>
        </div>
      </div>
      <div className="opacity-20 pointer-events-none select-none" aria-hidden="true">
        <div className="h-48 bg-muted/30 rounded-lg" />
      </div>
