        return (
          <Card className="rounded-xl border-2 border-violet-200 dark:border-violet-800 bg-gradient-to-r from-violet-50 to-purple-50 dark:from-violet-950/40 dark:to-purple-950/40 shadow-sm">
            <CardContent className="p-5">
              <div className="flex items-start gap-4">
                <div className="w-12 h-12 bg-violet-100 dark:bg-violet-900 rounded-xl flex items-center justify-center flex-shrink-0">
                  <Brain className="w-6 h-6 text-violet-600" />
                </div>
                <div className="flex-1">
                  <h4 className="font-bold text-foreground flex items-center gap-2">
                    AI Search Opportunity
                    <Badge className="bg-violet-100 text-violet-800 dark:bg-violet-900 dark:text-violet-200 text-[10px]">AEO Score: {score}/100</Badge>
                  </h4>
                  <p className="text-sm text-muted-foreground mt-1">
                    Optimizing for AI search engines could increase your featured snippet appearances by ~{snippetChance}%. AI-driven queries now represent ~{aiQueryShare}% of all searches.
                  </p>
                  <div className="mt-3 flex items-center gap-4">
                    <div className="bg-white dark:bg-violet-950 rounded-lg px-4 py-2 border border-violet-200 dark:border-violet-800">
                      <p className="text-xs text-muted-foreground">Potential AI citation rate</p>
                      <p className="text-lg font-bold text-violet-600">{snippetChance}%</p>
                      <p className="text-[10px] text-muted-foreground">of relevant AI queries</p>
                    </div>
                    <div className="bg-white dark:bg-violet-950 rounded-lg px-4 py-2 border border-violet-200 dark:border-violet-800">
                      <p className="text-xs text-muted-foreground">Growing query share</p>
                      <p className="text-lg font-bold text-violet-600">~{aiQueryShare}%</p>
                      <p className="text-[10px] text-muted-foreground">of searches use AI</p>
                    </div>
                  </div>
                  <p className="text-[10px] text-muted-foreground mt-2 italic">* Based on current AI search adoption trends. Sites optimized for AEO see significantly more AI-generated citations.</p>
                </div>
              </div>
            </CardContent>
          </Card>
