function GeoCompareTab({ url }: { url: string }) {
  const [competitorUrls, setCompetitorUrls] = useState<string[]>(["", ""]);
  const [comparisonResult, setComparisonResult] = useState<GeoComparisonResult | null>(null);
  const { toast } = useToast();

  const compareMutation = useMutation({
    mutationFn: async (urls: string[]) => {
      const response = await apiRequest("POST", "/api/geo-compare", { urls });
      return response.json();
    },
    onSuccess: (data: GeoComparisonResult) => setComparisonResult(data),
    onError: (error: Error) => toast({ title: "Comparison failed", description: error.message, variant: "destructive" }),
  });

  return (
    <div className="space-y-6">
      <Card className="p-6">
        <h3 className="text-lg font-semibold mb-4 flex items-center gap-2"><Users className="w-5 h-5" /> GEO Competitor Comparison</h3>
        <div className="space-y-3 mb-4">
          <div className="flex items-center gap-2">
            <Badge className="bg-primary text-primary-foreground shrink-0">Your URL</Badge>
            <Input value={url} disabled className="bg-muted" />
          </div>
          {competitorUrls.map((cu, i) => (
            <div key={i} className="flex items-center gap-2">
              <Badge variant="outline" className="shrink-0">Competitor {i + 1}</Badge>
              <Input
                value={cu}
                onChange={(e) => { const n = [...competitorUrls]; n[i] = e.target.value; setCompetitorUrls(n); }}
                placeholder="https://competitor.com"
              />
            </div>
          ))}
        </div>
        <Button onClick={() => {
          const allUrls = [url, ...competitorUrls.filter(u => u.trim())];
          if (allUrls.length < 2) { toast({ title: "Add at least one competitor URL", variant: "destructive" }); return; }
          compareMutation.mutate(allUrls);
        }} disabled={compareMutation.isPending}>
          {compareMutation.isPending ? <><Loader2 className="w-4 h-4 mr-2 animate-spin" />Comparing...</> : <><Users className="w-4 h-4 mr-2" />Compare GEO</>}
        </Button>
      </Card>

      {comparisonResult && (
        <div className="space-y-4">
          <Card className="p-4 bg-muted/50">
            <p className="text-sm">{comparisonResult.summary}</p>
          </Card>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
            {comparisonResult.analyses.map((a, i) => (
              <Card key={i} className={`p-4 ${a.url === comparisonResult.winner ? 'border-2 border-primary ring-2 ring-primary/20' : ''}`}>
                <div className="flex items-center justify-between mb-3">
                  <div className="text-sm font-medium truncate max-w-[200px]">{new URL(a.url).hostname}</div>
                  {a.url === comparisonResult.winner && <Badge className="bg-primary"><Trophy className="w-3 h-3 mr-1" />Winner</Badge>}
                </div>
                <div className="text-center mb-3">
                  <div className="text-3xl font-bold">{a.score}</div>
                  <Badge variant="outline">{a.rating}</Badge>
                </div>
                <div className="space-y-1 text-sm">
                  <div className="flex justify-between"><span className="text-muted-foreground">Authority</span><span className="font-medium">{a.sourceAuthorityScore}</span></div>
                  <div className="flex justify-between"><span className="text-muted-foreground">Fluency</span><span className="font-medium">{a.contentFluencyScore}</span></div>
                  <div className="flex justify-between"><span className="text-muted-foreground">Unique Value</span><span className="font-medium">{a.uniqueValueScore}</span></div>
                  <div className="flex justify-between"><span className="text-muted-foreground">Entity Opt.</span><span className="font-medium">{a.entityOptimizationScore}</span></div>
                  <div className="flex justify-between"><span className="text-muted-foreground">Multi-Format</span><span className="font-medium">{a.multiFormatScore}</span></div>
                </div>
                {a.keyStrengths.length > 0 && (
                  <div className="mt-3">
                    <div className="text-xs font-medium text-green-600 mb-1">Strengths</div>
                    <div className="flex flex-wrap gap-1">{a.keyStrengths.map((s, j) => <Badge key={j} variant="outline" className="text-xs text-green-600 border-green-200">{s}</Badge>)}</div>
                  </div>
                )}
                {a.keyWeaknesses.length > 0 && (
                  <div className="mt-2">
                    <div className="text-xs font-medium text-red-600 mb-1">Weaknesses</div>
                    <div className="flex flex-wrap gap-1">{a.keyWeaknesses.map((s, j) => <Badge key={j} variant="outline" className="text-xs text-red-600 border-red-200">{s}</Badge>)}</div>
                  </div>
                )}
              </Card>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

function BrokenLinksSection({ data, paidTier, onUpgrade }: { data: BrokenLinksResult; paidTier: string; onUpgrade: () => void }) {
