  return (
    <div className="space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
        <Card><CardContent className="pt-6 text-center"><ScoreBadge score={data.score} /><p className="text-sm text-muted-foreground mt-1">Health Score</p></CardContent></Card>
