        <Card><CardContent className="pt-6 text-center"><p className="text-2xl font-bold text-red-500">{data.brokenCount}</p><p className="text-sm text-muted-foreground">Broken</p></CardContent></Card>
        <Card><CardContent className="pt-6 text-center"><p className="text-2xl font-bold text-yellow-500">{data.redirectCount}</p><p className="text-sm text-muted-foreground">Redirects</p></CardContent></Card>
      </div>

      {(() => {
        const brokenCount = data.brokenLinks.filter(l => !l.statusText.startsWith("Skipped") && (l.statusCode === null || l.statusCode >= 400)).length;
        if (brokenCount === 0) return null;
        const equityLoss = Math.min(Math.round(brokenCount * 3), 30);
        return (
          <Card className="rounded-xl border-2 border-red-200 dark:border-red-800 bg-gradient-to-r from-red-50 to-orange-50 dark:from-red-950/40 dark:to-orange-950/40 shadow-sm">
            <CardContent className="p-5">
              <div className="flex items-start gap-4">
                <div className="w-12 h-12 bg-red-100 dark:bg-red-900 rounded-xl flex items-center justify-center flex-shrink-0">
                  <LinkIcon className="w-6 h-6 text-red-600" />
                </div>
                <div className="flex-1">
                  <h4 className="font-bold text-foreground flex items-center gap-2">
                    Link Equity Recovery
                    <Badge className="bg-red-100 text-red-800 dark:bg-red-900 dark:text-red-200 text-[10px]">{brokenCount} broken links</Badge>
                  </h4>
                  <p className="text-sm text-muted-foreground mt-1">
                    {brokenCount} broken link{brokenCount > 1 ? "s are" : " is"} leaking approximately {equityLoss}% of your page's link equity, negatively impacting your search rankings.
                  </p>
                  <div className="mt-3">
                    <div className="bg-white dark:bg-red-950 rounded-lg px-4 py-2 border border-red-200 dark:border-red-800 inline-block">
                      <p className="text-xs text-muted-foreground">Est. link equity loss</p>
                      <p className="text-lg font-bold text-red-600">~{equityLoss}%</p>
                      <p className="text-[10px] text-muted-foreground">recoverable by fixing links</p>
                    </div>
                  </div>
                  <p className="text-[10px] text-muted-foreground mt-2 italic">* Each broken link wastes crawl budget and loses link equity that could boost your rankings.</p>
                </div>
              </div>
            </CardContent>
          </Card>
        );
      })()}

      {paidTier === 'free' ? (
        <FreeKeyFindings
          items={data.brokenLinks.map((l: BrokenLink) => ({ name: l.url, impact: `${l.statusCode ?? 'N/A'} ${l.statusText} · ${l.type}`, status: 'FAIL' }))}
          onUpgrade={onUpgrade}
        />
      ) : (
        <Tabs defaultValue="broken" className="w-full">
          <TabsList className="flex-wrap h-auto">
            <TabsTrigger value="broken">Broken <Badge variant="outline" className="ml-1 text-red-600">{data.brokenCount}</Badge></TabsTrigger>
            <TabsTrigger value="redirected">Redirected <Badge variant="outline" className="ml-1 text-yellow-600">{data.redirectCount}</Badge></TabsTrigger>
            <TabsTrigger value="working">Working</TabsTrigger>
          </TabsList>

          <TabsContent value="broken">
            {data.brokenLinks.length > 0 ? (
              <Card data-testid="broken-links-list">
                <CardHeader>
                  <CardTitle className="text-lg flex items-center gap-2"><XCircle className="w-5 h-5 text-red-500" />Broken Links ({data.brokenLinks.length})</CardTitle>
                </CardHeader>
                <CardContent>
                  <div className="space-y-3">
                    {(showAll ? data.brokenLinks : data.brokenLinks.slice(0, 10)).map((link, i) => (
                      <BrokenLinkRow key={i} link={link} />
                    ))}
                    {data.brokenLinks.length > 10 && (
                      <Button variant="ghost" size="sm" onClick={() => setShowAll(!showAll)} className="w-full">
                        {showAll ? <ChevronUp className="w-4 h-4 mr-1" /> : <ChevronDown className="w-4 h-4 mr-1" />}
