              </div>
            )}
          </TabsContent>

          <TabsContent value="redirected">
            {data.redirectedLinks.length > 0 ? (
              <Card>
                <CardHeader>
                  <CardTitle className="text-lg flex items-center gap-2"><AlertTriangle className="w-5 h-5 text-yellow-500" />Redirected Links ({data.redirectedLinks.length})</CardTitle>
