function ImageOptSection({ data, paidTier, onUpgrade }: { data: ImageOptimizationResult; paidTier: string; onUpgrade: () => void }) {
  const imagesWithIssues = data.images.filter(img => img.issues.length > 0);

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
        <Card><CardContent className="pt-6 text-center"><ScoreBadge score={data.score} /><p className="text-sm text-muted-foreground mt-1">Optimization Score</p></CardContent></Card>
        <Card><CardContent className="pt-6 text-center"><p className="text-2xl font-bold">{data.totalImages}</p><p className="text-sm text-muted-foreground">Total Images</p></CardContent></Card>
        <Card><CardContent className="pt-6 text-center"><p className="text-2xl font-bold text-green-500">{data.modernFormatCount}</p><p className="text-sm text-muted-foreground">Modern Format</p></CardContent></Card>
        <Card><CardContent className="pt-6 text-center"><p className="text-2xl font-bold text-red-500">{data.oversizedImages}</p><p className="text-sm text-muted-foreground">Oversized</p></CardContent></Card>
      </div>

      {(() => {
        const issueImages = data.images.filter(img => img.issues.length > 0).length;
        if (issueImages === 0) return null;
        const oversizedCount = data.oversizedImages;
        const noLazy = data.totalImages - data.imagesWithLazyLoading;
        const loadReduction = Math.min(Math.round((oversizedCount * 0.4 + noLazy * 0.15) * 10) / 10, 5);
        const conversionBoost = Math.round(loadReduction * 7);
        return (
          <Card className="rounded-xl border-2 border-green-200 dark:border-green-800 bg-gradient-to-r from-green-50 to-emerald-50 dark:from-green-950/40 dark:to-emerald-950/40 shadow-sm">
            <CardContent className="p-5">
              <div className="flex items-start gap-4">
                <div className="w-12 h-12 bg-green-100 dark:bg-green-900 rounded-xl flex items-center justify-center flex-shrink-0">
                  <ImageIcon className="w-6 h-6 text-green-600" />
                </div>
                <div className="flex-1">
                  <h4 className="font-bold text-foreground flex items-center gap-2">
                    Page Speed Impact
                    <Badge className="bg-green-100 text-green-800 dark:bg-green-900 dark:text-green-200 text-[10px]">{issueImages} images need fixes</Badge>
                  </h4>
                  <p className="text-sm text-muted-foreground mt-1">
                    Optimizing your images could reduce page load time by ~{loadReduction}s, potentially improving conversion rates by ~{conversionBoost}%.
                  </p>
                  <div className="mt-3 flex items-center gap-4">
                    <div className="bg-white dark:bg-green-950 rounded-lg px-4 py-2 border border-green-200 dark:border-green-800">
                      <p className="text-xs text-muted-foreground">Est. load time reduction</p>
                      <p className="text-lg font-bold text-green-600">-{loadReduction}s</p>
