            {image.hasAlt && <Badge variant="outline" className="text-xs text-green-600">Alt ✓</Badge>}
            {!image.hasAlt && <Badge variant="outline" className="text-xs text-red-600">No Alt</Badge>}
            {image.hasLazyLoading && <Badge variant="outline" className="text-xs text-green-600">Lazy ✓</Badge>}
            {image.format && <Badge variant="outline" className="text-xs">{image.format}</Badge>}
            {image.fileSize && <Badge variant="outline" className="text-xs">{Math.round(image.fileSize / 1024)}KB</Badge>}
          </div>
          {hasIssues && (
            <ul className="mt-2 space-y-0.5">
              {image.issues.map((issue, j) => (<li key={j} className="text-xs text-muted-foreground">• {issue}</li>))}
            </ul>
          )}
        </div>
      </div>
    </div>
  );
}

export default function MasterAnalyzerPage() {
  const [result, setResult] = useState<MasterResult | null>(null);
  const { toast } = useToast();
  const [showEmailModal, setShowEmailModal] = useState(false);
  const [showPricingModal, setShowPricingModal] = useState(false);
  const [paidTier, setPaidTier] = useState<string>('free');
  const [emailSubmitting, setEmailSubmitting] = useState(false);
  const [emailCaptured, setEmailCaptured] = useState(false);
  const [pdfDownloading, setPdfDownloading] = useState(false);
  const [accessCode, setAccessCode] = useState<string>('');
  const [activeAccessCode, setActiveAccessCode] = useState<{ code: string; tier: string; scansRemaining: number; scansTotal: number } | null>(null);
  const [showAccessCodeInput, setShowAccessCodeInput] = useState(false);
  const [codeRedeeming, setCodeRedeeming] = useState(false);
  const [showAccessCodeDisplay, setShowAccessCodeDisplay] = useState(false);
  const [generatedAccessCode, setGeneratedAccessCode] = useState<string>('');
  const [darkMode, setDarkMode] = useState(() => {
    if (typeof window !== 'undefined') {
      const saved = localStorage.getItem('seo-analyzer-theme');
      if (saved) return saved === 'dark';
      return window.matchMedia('(prefers-color-scheme: dark)').matches;
    }
    return false;
  });
  const [showUpgradeEmailModal, setShowUpgradeEmailModal] = useState(false);
  const [upgradeEmail, setUpgradeEmail] = useState('');
  const [pendingUpgradeTier, setPendingUpgradeTier] = useState<'basic' | 'pro'>('basic');

  const form = useForm<z.infer<typeof formSchema>>({
    resolver: zodResolver(formSchema),
    defaultValues: { url: "" },
  });

  const fetchAccessCodeWithRetry = async (sessionId: string, tier: string, retries = 5) => {
    for (let i = 0; i < retries; i++) {
      try {
        if (i > 0) {
          try {
            await apiRequest("POST", "/api/verify-payment", { sessionId, tier });
          } catch {}
        }
        const response = await apiRequest("POST", "/api/get-access-code", { sessionId, tier });
        const data = await response.json();
        if (data.accessCode) {
          setGeneratedAccessCode(data.accessCode);
          setActiveAccessCode({ code: data.accessCode, tier: data.tier, scansRemaining: data.scansRemaining, scansTotal: data.scansTotal });
          setPaidTier(data.tier);
          setShowAccessCodeDisplay(true);
          return;
        }
      } catch {
        if (i < retries - 1) {
          await new Promise(resolve => setTimeout(resolve, 2000 * (i + 1)));
        }
      }
    }
    toast({ title: "Payment Processing", description: "Your payment was received but the access code is still being generated. Please try entering your session ID or contact support.", variant: "destructive" });
  };

  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    const payment = params.get('payment');
    const session = params.get('session');
    const tier = params.get('tier');

    if (payment === 'success' && session && tier && (tier === 'basic' || tier === 'pro')) {
      fetchAccessCodeWithRetry(session, tier);
      window.history.replaceState({}, '', '/');
    }
  }, []);

  useEffect(() => {
    document.documentElement.classList.toggle('dark', darkMode);
    localStorage.setItem('seo-analyzer-theme', darkMode ? 'dark' : 'light');
  }, [darkMode]);

  const handleRedeemCode = async () => {
    if (!accessCode.trim()) return;
    setCodeRedeeming(true);
    try {
      const response = await apiRequest("POST", "/api/redeem-code", { code: accessCode.trim() });
      const data = await response.json();
      if (data.valid) {
        setActiveAccessCode({ code: accessCode.trim().toUpperCase(), tier: data.tier, scansRemaining: data.scansRemaining, scansTotal: data.scansTotal });
        setPaidTier(data.tier);
        setShowAccessCodeInput(false);
        toast({ title: "Access Code Activated", description: `${data.tier === 'pro' ? 'Pro' : 'Basic'} tier unlocked with ${data.scansRemaining} scan${data.scansRemaining !== 1 ? 's' : ''} remaining.` });
      } else {
        toast({ title: "No Scans Left", description: "This access code has no remaining scans.", variant: "destructive" });
      }
    } catch (error: any) {
      toast({ title: "Invalid Code", description: error.message || "Could not validate access code", variant: "destructive" });
    } finally {
      setCodeRedeeming(false);
    }
  };

  const analyzeMutation = useMutation({
    mutationFn: async (data: { url: string }) => {
      const payload: any = { url: data.url };
      if (activeAccessCode) {
        payload.accessCode = activeAccessCode.code;
      }
      const response = await apiRequest("POST", "/api/master-analyze", payload);
      return response.json();
    },
    onSuccess: (data: MasterResult) => {
      const remaining = (data as any).remaining;
      const returnedTier = (data as any).paidTier;
      const scansLeft = (data as any).scansRemaining;

      if (returnedTier && returnedTier !== 'free') {
        setPaidTier(returnedTier);
      }

      if (activeAccessCode && scansLeft !== undefined) {
        setActiveAccessCode(prev => prev ? { ...prev, scansRemaining: scansLeft } : null);
      }

      const scanInfo = activeAccessCode
        ? `${scansLeft} scan${scansLeft !== 1 ? 's' : ''} remaining.`
        : (remaining !== undefined ? `${remaining} free ${remaining === 1 ? 'analysis' : 'analyses'} remaining today.` : '');

      toast({
        title: "Master Analysis Complete",
        description: `All tools finished analyzing ${data.url}${scanInfo ? `. ${scanInfo}` : ''}`
      });
      setResult(data);
      setEmailCaptured(false);
    },
    onError: (error: any) => {
      const isRateLimit = error.message?.includes('limit') || error.message?.includes('429');
      const isNoScans = error.message?.includes('No scans remaining');
      toast({ 
        title: isRateLimit ? "Daily Limit Reached" : isNoScans ? "No Scans Left" : "Analysis Failed", 
        description: isRateLimit ? "You've used all 3 free analyses today. Upgrade for unlimited access." : isNoScans ? "Your access code has no scans remaining. Purchase a new plan for more scans." : (error.message || "Something went wrong"), 
        variant: "destructive" 
      });
    },
  });

  const onSubmit = (values: z.infer<typeof formSchema>) => {
    analyzeMutation.mutate(values);
  };

  const handleDownloadPdf = async (tier: 'free' | 'basic' | 'pro' = 'free') => {
    if (!result || !result.sessionId) return;

    const effectiveTier = paidTier !== 'free' ? paidTier as 'free' | 'basic' | 'pro' : tier;

    if (effectiveTier === 'free' && !emailCaptured) {
      setShowEmailModal(true);
      return;
    }

    if (effectiveTier !== 'free' && paidTier === 'free') {
      setShowPricingModal(true);
      return;
    }

    setPdfDownloading(true);
    try {
      const response = await apiRequest("POST", "/api/master-pdf", { sessionId: result.sessionId, tier: effectiveTier });
      const blob = await response.blob();
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement("a");
      a.style.display = "none";
      a.href = url;
      a.download = `seo-report-${effectiveTier}-${result.url.replace(/[^a-zA-Z0-9]/g, "-")}.pdf`;
      document.body.appendChild(a);
      a.click();
      window.URL.revokeObjectURL(url);
      document.body.removeChild(a);
    } catch (error) {
      toast({ title: "PDF Download Failed", description: "Could not generate the PDF report", variant: "destructive" });
    } finally {
      setPdfDownloading(false);
    }
  };

  const handleEmailSubmit = async (email: string) => {
    if (!result?.sessionId) return;
    setEmailSubmitting(true);
    try {
      await apiRequest("POST", "/api/capture-email", { email, sessionId: result.sessionId });
      setEmailCaptured(true);
      setShowEmailModal(false);
      toast({ title: "Email saved!", description: "Your free report is downloading..." });
      setPdfDownloading(true);
      const response = await apiRequest("POST", "/api/master-pdf", { sessionId: result.sessionId, tier: 'free' });
      const blob = await response.blob();
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement("a");
      a.style.display = "none";
      a.href = url;
      a.download = `seo-report-free-${result.url.replace(/[^a-zA-Z0-9]/g, "-")}.pdf`;
      document.body.appendChild(a);
      a.click();
      window.URL.revokeObjectURL(url);
      document.body.removeChild(a);
      setPdfDownloading(false);
    } catch (error) {
      toast({ title: "Error", description: "Could not save email", variant: "destructive" });
    } finally {
      setEmailSubmitting(false);
    }
  };

  const handleUpgrade = async (tier: 'basic' | 'pro') => {
    if (!result?.sessionId) return;
    setPendingUpgradeTier(tier);
    try {
      const response = await fetch("/api/config");
      if (!response.ok) {
        setShowUpgradeEmailModal(true);
        return;
      }
      const config = await response.json();
      if (!config.stripeConfigured) {
        setShowUpgradeEmailModal(true);
        return;
      }
      await executeUpgrade(tier, '');
    } catch {
      setShowUpgradeEmailModal(true);
    }
  };

  const executeUpgrade = async (tier: 'basic' | 'pro', email: string) => {
    if (!result?.sessionId) return;
    try {
      const response = await apiRequest("POST", "/api/create-checkout", { sessionId: result.sessionId, tier, email: email || undefined });
      const data = await response.json();
      if (data.devMode && data.accessCode) {
        setGeneratedAccessCode(data.accessCode);
        setActiveAccessCode({ code: data.accessCode, tier: data.tier, scansRemaining: data.scansRemaining, scansTotal: 5 });
        setPaidTier(data.tier);
        setShowAccessCodeDisplay(true);
        toast({ title: "Access Code Generated", description: `Your code: ${data.accessCode}` });
      } else if (data.url) {
