        </div>
      </header>

      <div className="container mx-auto px-4 py-8">
        <div className="text-center mb-8">
          <div className="inline-flex items-center gap-2 px-4 py-1.5 rounded-full bg-primary/10 text-primary text-sm font-medium mb-4">
            <Zap className="w-4 h-4" />
            All 8 Tools in One Click
          </div>
          <h2 className="text-3xl font-bold mb-2">Master SEO Analyzer</h2>
          <p className="text-muted-foreground max-w-2xl mx-auto">
            Enter a URL and run every analysis tool at once: SEO audit, Google Ads landing page experience, AEO readiness, GEO readiness, broken links, image optimization, internal linking, and sitemap validation.
          </p>
        </div>

        <Card className="mb-8 border-primary/20 shadow-lg">
          <CardContent className="pt-6">
            <Form {...form}>
              <form onSubmit={form.handleSubmit(onSubmit)} className="flex gap-3">
                <FormField
                  control={form.control}
