                <Button type="submit" disabled={analyzeMutation.isPending} className="h-12 px-6" data-testid="master-analyze">
                  {analyzeMutation.isPending ? (
                    <><Loader2 className="w-4 h-4 mr-2 animate-spin" />Analyzing...</>
