                      <Button size="sm" variant="outline" onClick={handleRedeemCode} disabled={codeRedeeming || !accessCode.trim()} className="h-8 text-xs">
                        {codeRedeeming ? <Loader2 className="w-3 h-3 animate-spin" /> : "Activate"}
                      </Button>
                      <Button size="sm" variant="ghost" onClick={() => { setShowAccessCodeInput(false); setAccessCode(''); }} className="h-8 text-xs text-muted-foreground">
