                  <div className="text-lg font-semibold mb-3">Basic Report</div>
                  <ul className="space-y-2 text-sm text-muted-foreground mb-4">
                    <li className="flex items-start gap-2"><CheckCircle2 className="w-4 h-4 text-blue-500 mt-0.5 shrink-0" />5 URL scans</li>
                    <li className="flex items-start gap-2"><CheckCircle2 className="w-4 h-4 text-blue-500 mt-0.5 shrink-0" />Full technical breakdown across all 8 tools</li>
                    <li className="flex items-start gap-2"><CheckCircle2 className="w-4 h-4 text-blue-500 mt-0.5 shrink-0" />Detailed scores and check results</li>
                    <li className="flex items-start gap-2"><XCircle className="w-4 h-4 text-gray-300 mt-0.5 shrink-0" />Fix instructions & recommendations</li>
                    <li className="flex items-start gap-2"><XCircle className="w-4 h-4 text-gray-300 mt-0.5 shrink-0" />30-minute expert consultation</li>
