import Stripe from 'stripe';

const stripeSecretKey = process.env.STRIPE_SECRET_KEY;

let stripe: Stripe | null = null;

if (stripeSecretKey) {
  stripe = new Stripe(stripeSecretKey, { apiVersion: '2024-12-18.acacia' as any });
}

export function isStripeConfigured(): boolean {
  return !!stripeSecretKey && !!stripe;
}

export async function createCheckoutSession(params: {
  sessionId: string;
  tier: 'basic' | 'pro';
  url: string;
  email?: string;
  successUrl: string;
  cancelUrl: string;
}): Promise<{ url: string } | null> {
  if (!stripe) return null;

  const prices: Record<string, { amount: number; name: string; description: string }> = {
    basic: {
      amount: 2900,
      name: 'Basic SEO Report (5 scans)',
      description: `Full technical breakdown for ${params.url} — includes 5 URL scans`,
    },
    pro: {
      amount: 24900,
      name: 'Pro SEO Report + Consultation (5 scans)',
      description: `Complete report with fix guides + 30-min consultation for ${params.url} — includes 5 URL scans`,
    },
  };

  const product = prices[params.tier];

  const sessionConfig: any = {
    payment_method_types: ['card'],
    line_items: [
      {
        price_data: {
          currency: 'eur',
          product_data: {
            name: product.name,
            description: product.description,
          },
          unit_amount: product.amount,
        },
        quantity: 1,
      },
    ],
    mode: 'payment',
    success_url: params.successUrl,
    cancel_url: params.cancelUrl,
    metadata: {
      sessionId: params.sessionId,
      tier: params.tier,
      analyzedUrl: params.url,
      email: params.email || '',
    },
  };

  if (params.email) {
    sessionConfig.customer_email = params.email;
  }

  const session = await stripe.checkout.sessions.create(sessionConfig);

  return { url: session.url! };
}

export async function verifyWebhookSignature(
  payload: Buffer,
  signature: string,
  webhookSecret: string
): Promise<Stripe.Event | null> {
  if (!stripe) return null;
  try {
    return stripe.webhooks.constructEvent(payload, signature, webhookSecret);
  } catch {
    return null;
  }
}

export { stripe };

